The correct query should be:

SELECT ?year WHERE {
  ?edition wdt:P361 wd:Q14496 ;
           wdt:P1546 wd:Q612 ;
           wdt:P585 ?date .
  BIND(YEAR(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1

